const itemList = document.getElementById('itemList');
const headerForm = document.getElementById('headerForm');

// Initialize the app
function init() {
    headerForm.innerHTML = '';
    data.form_fields.forEach(field => {
        const div = document.createElement('div');
        div.className = 'form-group';
        div.innerHTML = `<label>${field}</label><input type="text" id="field-${field}" class="header-input">`;
        headerForm.appendChild(div);
    });

    itemList.innerHTML = '';
    data.items.forEach(item => {
        const card = document.createElement('div');
        card.className = 'item-card';
        card.innerHTML = `
            <span class="item-name">${item}</span>
            <div class="input-row">
                <input type="number" class="qty" placeholder="0" min="0">
                <select class="unit">
                    <option value="kg">કિ.</option>
                    <option value="g">ગ્રામ</option>
                    <option value="નંગ">નંગ</option>
                </select>
            </div>
        `;
        itemList.appendChild(card);
    });
}

// Filter Search
function filterItems() {
    const query = document.getElementById('searchInput').value.toLowerCase();
    document.querySelectorAll('.item-card').forEach(card => {
        const name = card.querySelector('.item-name').innerText.toLowerCase();
        card.style.display = name.includes(query) ? 'flex' : 'none';
    });
}

// Generate PDF
function generatePDF() {
    // 1. Collect the items that have a quantity entered
    const orderItems = [];
    document.querySelectorAll('.item-card').forEach(card => {
        const q = card.querySelector('.qty').value;
        if (q > 0) {
            orderItems.push({
                name: card.querySelector('.item-name').innerText,
                qty: q,
                unit: card.querySelector('.unit').value
            });
        }
    });

    // 2. Alert if nothing was selected
    if (orderItems.length === 0) {
        alert("કૃપા કરીને પહેલા સંખ્યા લખો!");
        return;
    }

    // 3. Build the HTML for the printable page
    let printHTML = `
    <html>
    <head>
        <title>Murlidhar Caterers Order</title>
        <style>
            body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; }
            .header { text-align: center; border-bottom: 3px solid #e60000; padding-bottom: 10px; margin-bottom: 20px; }
            .header h1 { color: #e60000; margin: 0; font-size: 28px; }
            .header p { margin: 5px 0; font-size: 14px; }
            .customer-info { display: flex; flex-wrap: wrap; gap: 15px; margin-bottom: 25px; }
            .info-item { width: 45%; font-size: 14px; border-bottom: 1px dotted #ccc; padding: 5px 0; }
            table { width: 100%; border-collapse: collapse; margin-top: 15px; }
            th { background-color: #e60000; color: white; border: 1px solid #ddd; padding: 10px; text-align: left; }
            td { border: 1px solid #ddd; padding: 10px; }
            .footer { margin-top: 40px; font-size: 12px; border-top: 1px solid #eee; padding-top: 10px; }
            @media print {
                .no-print { display: none; }
                body { padding: 0; }
            }
        </style>
    </head>
    <body>
        <div class="header">
            <h1>${data.caterer_details.name}</h1>
            <p>${data.caterer_details.contact}</p>
            <p>${data.caterer_details.address}</p>
        </div>

        <div class="customer-info">
    `;

    // 4. Add the header form fields (Name, Date, etc.)
    data.form_fields.forEach(f => {
        const val = document.getElementById(`field-${f}`).value;
        if (val) {
            printHTML += `<div class="info-item"><strong>${f}:</strong> ${val}</div>`;
        }
    });

    printHTML += `
        </div>
        <table>
            <thead>
                <tr>
                    <th>વસ્તુનું નામ (Item)</th>
                    <th style="text-align: center;">જથ્થો (Qty)</th>
                    <th style="text-align: center;">એકમ (Unit)</th>
                </tr>
            </thead>
            <tbody>
    `;

    // 5. Add the selected items to the table
    orderItems.forEach(item => {
        printHTML += `
            <tr>
                <td>${item.name}</td>
                <td style="text-align: center;">${item.qty}</td>
                <td style="text-align: center;">${item.unit}</td>
            </tr>
        `;
    });

    printHTML += `
            </tbody>
        </table>

        <div class="footer">
            <strong>નિયમો અને શરતો:</strong>
            <ul style="padding-left: 20px;">
                ${data.terms.map(t => `<li>${t}</li>`).join('')}
            </ul>
        </div>
    </body>
    </html>
    `;

    // 6. Open a new window, write the content, and trigger print
    const printWindow = window.open('', '_blank');
    printWindow.document.write(printHTML);
    printWindow.document.close();
    
    // Slight delay to ensure fonts render before the print dialog opens
    setTimeout(() => {
        printWindow.print();
        // Optional: close the window after printing
        // printWindow.close(); 
    }, 500);
}

init();